import sys
from collections import defaultdict

class TrieNode:
    def __init__(self):
        self.children = defaultdict(TrieNode)
        self.is_word = False

class Solution:
    def insert(self, root, word):
        node = root
        for ch in word:
            node = node.children[ch]
        node.is_word = True

    def search(self, root, word):
        node = root
        for ch in word:
            if ch not in node.children:
                return False
            node = node.children[ch]
        return node.is_word

if __name__ == '__main__':
    words = sys.stdin.readline().strip().split('
')
    solution = Solution()
    n, *words = map(str, words)
    for word in words:
        solution.insert(None, word)
        print(solution.search(None, word))

