#include <iostream>
#include <string>
#include <vector>

using namespace std;

class TrieNode{ 
public:
    TrieNode* children[26];
    bool is_word=false;
    TrieNode(){
        for(int i=0;i<26;i++)
            children[i]=nullptr;
    }
};

class Solution {
public:
    void insert(TrieNode* root, const string& word){
        TrieNode* node = root;
        for(int i=0;i<word.size();i++){
            char ch = word[i];
            if(node->children[ch-'a']==nullptr)
                node->children[ch-'a'] = new TrieNode();
            node = node->children[ch-'a'];
        }
        node->is_word=true;
    }

    bool search(TrieNode* root, const string& word){
        TrieNode* node = root;
        for(int i=0;i<word.size();i++){
            char ch = word[i];
            if(node->children[ch-'a']==nullptr)
                return false;
            node = node->children[ch-'a'];
        }
        return node->is_word;
    }

    void solve(){
        string s;
        while(getline(cin,s)){
            solution.insert(nullptr, s);
            cout<<solution.search(nullptr, s)<<endl;
        }
    }
};

int main(){
    Solution solution;
    solution.solve();
    return 0;
}
